#include <stdio.h>

int findNumberOfLIS(int* nums, int numsSize) {
    int dp[numsSize];
    int ct[numsSize];
    int maxi = 1;
    for (int i = 0; i < numsSize; i++) {
        dp[i] = 1;
        ct[i] = 1;
    }
    for (int i = 0; i < numsSize; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[j] < nums[i] && dp[j] + 1 > dp[i]) {
                dp[i] = dp[j] + 1;
                ct[i] = ct[j];
            } else if (nums[j] < nums[i] && dp[j] + 1 == dp[i]) {
                ct[i] += ct[j];
            }
        }
        maxi = (maxi > dp[i]) ? maxi : dp[i];
    }
    int countLIS = 0;
    for (int i = 0; i < numsSize; i++) {
        if (dp[i] == maxi) {
            countLIS += ct[i];
        }
    }
    return countLIS;
}

